select * from activity

    status != '-1'

        and activity_name like CONCAT('%', #{activityName}, '%')


        and status = #{status}


        and start_time >= #{startTime}


        and end_time >= #{endTime}


order by update_time desc

SELECT activity.* FROM activity INNER JOIN activity_participant ON activity.id = activity_participant.activity_id WHERE activity_participant.user_id = #{userId} AND activity_participant.status = '1' AND activity.status != '-1'
AND activity.status = #{status}
ORDER BY activity.update_time DESC
